    //         initializeTree(self);
    //     }

    //     require(!self.nodes[key.tokenId].initialized, "TokenId already exists");

    //     uint256 newNodeId = key.tokenId;
    //     self.nodes[newNodeId] = Node(key, 1, Color.RED, NULL_NODE, NULL_NODE, NULL_NODE, true);

    //     uint256 y = NULL_NODE;
