    //         self.nodes[x].size++;
    //         if (compare(key, PriceToken(self.nodes[x].key.tokenId, self.nodes[x].key.price)) < 0) {
    //             x = self.nodes[x].left;
    //         } else {
    //             x = self.nodes[x].right;
    //         }
