contracts/OrderStatisticsTreeTest.sol.content:
// SPDX-License-Identifier: MIT
// contracts/RedBlackTreeLibTest.sol
pragma solidity ^0.8.0;
// pragma experimental ABIEncoderV2;

import "./OrderStatisticsTree.sol";

contract OrderStatisticsTreeTest {
    using OrderStatisticsTree for OrderStatisticsTree.Tree;
    OrderStatisticsTree.Tree private tree;

    function initializeTree(OrderStatisticsTree.ComparatorType comparatorType) public {
        tree.initializeTree(comparatorType);
    }

    function insert(uint256 price, uint256 tokenId) public {
        OrderStatisticsTree.PriceToken memory newToken = OrderStatisticsTree.PriceToken({
            price: price,
            tokenId: tokenId
        });
        // tree.insert(newToken, tokenId);
        tree.insertPriceToken(newToken);
    }

    // function printTree() public view returns (string memory) {
    //     return tree.getTreeStructure();
    // }

    function remove(uint256 tokenId) public {
        tree.remove(tokenId);
    }

    function getPriceTokenByIndex(uint256 index) public view returns (OrderStatisticsTree.PriceToken memory) {
        return tree.select(index + 1).priceToken;
    }

    function getPriceTokenByIndexZero() public view returns (OrderStatisticsTree.PriceToken memory) {
        return tree.select(0).priceToken;
    }

    function getNodeByTokenId(uint256 tokenId) public view returns (OrderStatisticsTree.Node memory) {
        return tree.nodes[tokenId];
    }

    function getPriceTokenByTokenId(uint256 tokenId) public view returns (OrderStatisticsTree.PriceToken memory) {
        return tree.nodes[tokenId].priceToken;
    }

    function getMin() public view returns (OrderStatisticsTree.PriceToken memory) {
        return getPriceTokenByTokenId(tree.minimum(tree.root));
    }

    // function getMax() public view returns (RedBlackTreeLib.PriceToken memory) {
    //     return tree.getPriceTokenByTokenId(tree.last());
    // }

    function size() public view returns (uint256) {
        return tree.nodes[tree.root].size;
    }

    function root() public view returns (uint256) {
        return tree.root;
    }

        function height() public view returns (uint256) {
        return tree.getTreeHeight();
    }

    function getPriceTokenRange(uint256 start, uint256 count) 
        public view returns (OrderStatisticsTree.PriceToken[] memory)
    {
        // return tree.getPriceTokenRange_PriceTokenId(start, count);
        return tree.getPriceTokenRange_PriceTokenId(start, count, true);
    }

    function getPriceTokenRangeReverse(uint256 start, uint256 count) 
        public view returns (OrderStatisticsTree.PriceToken[] memory)
    {
        // return tree.getPriceTokenRange_PriceTokenIdReverse(start, count);
        return tree.getPriceTokenRange_PriceTokenId(start, count, false);
    }
}

contracts/OriginalNFT.sol.content:
// SPDX-License-Identifier: MIT

pragma solidity ^0.8.0;

	// import "https://github.com/XDCFoundation/XRC721-SMART-CONTRACT/blob/main/XRC721/IXRC721.sol";
	// import "https://github.com/XDCFoundation/XRC721-SMART-CONTRACT/blob/main/XRC721/IXRC721Receiver.sol";
	// import "https://github.com/XDCFoundation/XRC721-SMART-CONTRACT/blob/main/XRC721/SafeMath.sol";
	// import "https://github.com/XDCFoundation/XRC721-SMART-CONTRACT/blob/main/XRC721/Address.sol";
	// import "https://github.com/XDCFoundation/XRC721-SMART-CONTRACT/blob/main/XRC721/Counters.sol";
	// import "https://github.com/XDCFoundation/XRC721-SMART-CONTRACT/blob/main/XRC721/XRC165.sol";
    import "./external/IXRC721.sol";
    import "./external/IXRC721Receiver.sol";
    import "./external/SafeMath.sol";
    import "./external/Address.sol";
    import "./external/Counters.sol";
    import "./external/XRC165.sol";

	/**
	 * @title XRC721 Non-Fungible Token Standard basic implementation
	 */
	contract OriginalNFT is XRC165, IXRC721 {
	    using SafeMath for uint256;
	    using Address for address;
	    using Counters for Counters.Counter;

	    // Equals to `bytes4(keccak256("onXRC721Received(address,address,uint256,bytes)"))`
	    // which can be also obtained as `IXRC721Receiver(0).onXRC721Received.selector`
	    bytes4 private constant _XRC721_RECEIVED = 0x150b7a02;

	    // Mapping from token ID to owner
	    mapping (uint256 => address) private _tokenOwner;

	    // Mapping from token ID to approved address
	    mapping (uint256 => address) private _tokenApprovals;

	    // Mapping from owner to number of owned token
	    mapping (address => Counters.Counter) private _ownedTokensCount;

	    // Mapping from owner to operator approvals
	    mapping (address => mapping (address => bool)) private _operatorApprovals;

		mapping(uint256 => string) private _tokenURIs;

		// bool already_minted = false;
		// bool already_set_token_uri = false;

	    /*
	     *     bytes4(keccak256('balanceOf(address)')) == 0x70a08231
	     *     bytes4(keccak256('ownerOf(uint256)')) == 0x6352211e
	     *     bytes4(keccak256('approve(address,uint256)')) == 0x095ea7b3
	     *     bytes4(keccak256('getApproved(uint256)')) == 0x081812fc
	     *     bytes4(keccak256('setApprovalForAll(address,bool)')) == 0xa22cb465
	     *     bytes4(keccak256('isApprovedForAll(address,address)')) == 0xe985e9c
	     *     bytes4(keccak256('transferFrom(address,address,uint256)')) == 0x23b872dd
	     *     bytes4(keccak256('safeTransferFrom(address,address,uint256)')) == 0x42842e0e
	     *     bytes4(keccak256('safeTransferFrom(address,address,uint256,bytes)')) == 0xb88d4fde
	     *
	     *     => 0x70a08231 ^ 0x6352211e ^ 0x095ea7b3 ^ 0x081812fc ^
	     *        0xa22cb465 ^ 0xe985e9c ^ 0x23b872dd ^ 0x42842e0e ^ 0xb88d4fde == 0x80ac58cd
	     */
	    bytes4 private constant _INTERFACE_ID_XRC721 = 0x80ac58cd;

	     // Token name
    string private _name;

    // Token symbol
    string private _symbol;
    address constant private originalOwnerAddress = 0xb3C7c1c14f83f57370fcE247Ec359BE8584C3902;
	string constant private tokenuri = "{\"name\": \"Ethereum Killer\",\"description\": \"XDC kills Ethereum in the rainy night with a sharp knife in bloody fashion while XDC's four henchmen look on from behind, savoring every moment. A3 size. 500 DPI.\",\"image\": \"ipfs://QmUWTcu7yvNrih7f5w6Kzt1rKc7qL6J9pXdTKnuPq948Bi\",\"external_url\": \"https://xdc.art/ethereumkiller.png\"}";

    constructor () public {
        // register the supported interfaces to conform to XRC721 via XRC165
       _name = "Ethereum Killer";
        _symbol = "ETHKILLER";
        _registerInterface(_INTERFACE_ID_XRC721);

		_mint(originalOwnerAddress, 1);
		_setTokenURI(1, tokenuri);

    }
	    function balanceOf(address owner) public view override returns (uint256) {
	        require(owner != address(0), "XRC721: balance query for the zero address");

	        return _ownedTokensCount[owner].current();
	    }
	    function name() public view returns (string memory){
            return _name;
        }


        function symbol() public view returns (string memory){
            return _symbol;
        }


	    /**
	     * @dev Gets the owner of the specified token ID.
	     * @param tokenId uint256 ID of the token to query the owner of
	     * @return address currently marked as the owner of the given token ID
	     */
	    function ownerOf(uint256 tokenId) public view override returns (address) {
	        address owner = _tokenOwner[tokenId];
	        require(owner != address(0), "XRC721: owner query for nonexistent token");

	        return owner;
	    }

	    /**
	     * @dev Approves another address to transfer the given token ID
	     * The zero address indicates there is no approved address.
	     * There can only be one approved address per token at a given time.
	     * Can only be called by the token owner or an approved operator.
	     * @param to address to be approved for the given token ID
	     * @param tokenId uint256 ID of the token to be approved
	     */
	    function approve(address to, uint256 tokenId) public override{
	        address owner = ownerOf(tokenId);
	        require(to != owner, "XRC721: approval to current owner");

	        require(msg.sender == owner || isApprovedForAll(owner, msg.sender),
	            "XRC721: approve caller is not owner nor approved for all"
	        );

	        _tokenApprovals[tokenId] = to;
	        emit Approval(owner, to, tokenId);
	    }

	    /**
	     * @dev Gets the approved address for a token ID, or zero if no address set
	     * Reverts if the token ID does not exist.
	     * @param tokenId uint256 ID of the token to query the approval of
	     * @return address currently approved for the given token ID
	     */
	    function getApproved(uint256 tokenId) public view override returns (address) {
	        require(_exists(tokenId), "XRC721: approved query for nonexistent token");

	        return _tokenApprovals[tokenId];
	    }

	    /**
	     * @dev Sets or unsets the approval of a given operator
	     * An operator is allowed to transfer all tokens of the sender on their behalf.
	     * @param to operator address to set the approval
	     * @param approved representing the status of the approval to be set
	     */
	    function setApprovalForAll(address to, bool approved) public override {
	        require(to != msg.sender, "XRC721: approve to caller");

	        _operatorApprovals[msg.sender][to] = approved;
	        emit ApprovalForAll(msg.sender, to, approved);
	    }

	    /**
	     * @dev Tells whether an operator is approved by a given owner.
	     * @param owner owner address which you want to query the approval of
	     * @param operator operator address which you want to query the approval of
	     * @return bool whether the given operator is approved by the given owner
	     */
	    function isApprovedForAll(address owner, address operator) public view override returns (bool) {
	        return _operatorApprovals[owner][operator];
	    }

	    /**
	     * @dev Transfers the ownership of a given token ID to another address.
	     * Usage of this method is discouraged, use `safeTransferFrom` whenever possible.
	     * Requires the msg.sender to be the owner, approved, or operator.
	     * @param from current owner of the token
	     * @param to address to receive the ownership of the given token ID
	     * @param tokenId uint256 ID of the token to be transferred
	     */
	    function transferFrom(address from, address to, uint256 tokenId) public override {
	        //solhint-disable-next-line max-line-length
	        require(_isApprovedOrOwner(msg.sender, tokenId), "XRC721: transfer caller is not owner nor approved");

	        _transferFrom(from, to, tokenId);
	    }

	    /**
	     * @dev Safely transfers the ownership of a given token ID to another address
	     * If the target address is a contract, it must implement `onXRC721Received`,
	     * which is called upon a safe transfer, and return the magic value
	     * `bytes4(keccak256("onXRC721Received(address,address,uint256,bytes)"))`; otherwise,
	     * the transfer is reverted.
	     * Requires the msg.sender to be the owner, approved, or operator
	     * @param from current owner of the token
	     * @param to address to receive the ownership of the given token ID
	     * @param tokenId uint256 ID of the token to be transferred
	     */
	    function safeTransferFrom(address from, address to, uint256 tokenId) public override {
	        safeTransferFrom(from, to, tokenId, "");
	    }

	    /**
	     * @dev Safely transfers the ownership of a given token ID to another address
	     * If the target address is a contract, it must implement `onXRC721Received`,
	     * which is called upon a safe transfer, and return the magic value
	     * `bytes4(keccak256("onXRC721Received(address,address,uint256,bytes)"))`; otherwise,
	     * the transfer is reverted.
	     * Requires the msg.sender to be the owner, approved, or operator
	     * @param from current owner of the token
	     * @param to address to receive the ownership of the given token ID
	     * @param tokenId uint256 ID of the token to be transferred
	     * @param _data bytes data to send along with a safe transfer check
	     */
	    function safeTransferFrom(address from, address to, uint256 tokenId, bytes memory _data) public override {
	        transferFrom(from, to, tokenId);
	        require(_checkOnXRC721Received(from, to, tokenId, _data), "XRC721: transfer to non XRC721Receiver implementer");
	    }

	    /**
	     * @dev Returns whether the specified token exists.
	     * @param tokenId uint256 ID of the token to query the existence of
	     * @return bool whether the token exists
	     */
	    function _exists(uint256 tokenId) internal view returns (bool) {
	        address owner = _tokenOwner[tokenId];
	        return owner != address(0);
	    }

	    /**
	     * @dev Returns whether the given spender can transfer a given token ID.
	     * @param spender address of the spender to query
	     * @param tokenId uint256 ID of the token to be transferred
	     * @return bool whether the msg.sender is approved for the given token ID,
	     * is an operator of the owner, or is the owner of the token
	     */
	    function _isApprovedOrOwner(address spender, uint256 tokenId) internal view returns (bool) {
	        require(_exists(tokenId), "XRC721: operator query for nonexistent token");
	        address owner = ownerOf(tokenId);
	        return (spender == owner || getApproved(tokenId) == spender || isApprovedForAll(owner, spender));
	    }

	    /**
	     * @dev Internal function to mint a new token.
	     * Reverts if the given token ID already exists.
	     * @param to The address that will own the minted token
	     * @param tokenId uint256 ID of the token to be minted
	     */
	    function _mint(address to, uint256 tokenId) internal {
	        require(to != address(0), "XRC721: mint to the zero address");
	        require(!_exists(tokenId), "XRC721: token already minted");

	        _tokenOwner[tokenId] = to;
	        _ownedTokensCount[to].increment();

	        emit Transfer(address(0), to, tokenId);
	    }

		// function mint(address to, uint256 tokenId) external returns (bool) {
		// 	require(already_minted == false, "XRC721: token already minted");

		// 	_mint(to, tokenId);
		// 	return true;
		// }

		// function _setTokenURI(uint256 tokenId, string calldata uri) internal {
		function _setTokenURI(uint256 tokenId, string memory uri) internal {
			require(_exists(tokenId), "XRC721Metadata: URI set of nonexistent token");
			// require(already_set_token_uri == false, "XRC721: token already set token URI");
			_tokenURIs[tokenId] = uri;
		}

		function tokenURI(uint256 tokenId) external view returns (string memory) {
			require(_exists(tokenId), "XRC721Metadata: URI query for nonexistent token");
			return _tokenURIs[tokenId];
		}



	    /**
	     * @dev Internal function to burn a specific token.
	     * Reverts if the token does not exist.
	     * Deprecated, use _burn(uint256) instead.
	     * @param owner owner of the token to burn
	     * @param tokenId uint256 ID of the token being burned
	     */
	    function _burn(address owner, uint256 tokenId) internal {
	        require(ownerOf(tokenId) == owner, "XRC721: burn of token that is not own");

	        _clearApproval(tokenId);

	        _ownedTokensCount[owner].decrement();
	        _tokenOwner[tokenId] = address(0);

	        emit Transfer(owner, address(0), tokenId);
	    }

	    /**
	     * @dev Internal function to burn a specific token.
	     * Reverts if the token does not exist.
	     * @param tokenId uint256 ID of the token being burned
	     */
	    function _burn(uint256 tokenId) internal {
	        _burn(ownerOf(tokenId), tokenId);
	    }

	    /**
	     * @dev Internal function to transfer ownership of a given token ID to another address.
	     * As opposed to transferFrom, this imposes no restrictions on msg.sender.
	     * @param from current owner of the token
	     * @param to address to receive the ownership of the given token ID
	     * @param tokenId uint256 ID of the token to be transferred
	     */
	    function _transferFrom(address from, address to, uint256 tokenId) internal {
	        require(ownerOf(tokenId) == from, "XRC721: transfer of token that is not own");
	        require(to != address(0), "XRC721: transfer to the zero address");

	        _clearApproval(tokenId);

	        _ownedTokensCount[from].decrement();
	        _ownedTokensCount[to].increment();

	        _tokenOwner[tokenId] = to;

	        emit Transfer(from, to, tokenId);
	    }

	    /**
	     * @dev Internal function to invoke `onXRC721Received` on a target address.
	     * The call is not executed if the target address is not a contract.
	     *
	     * This function is deprecated.
	     * @param from address representing the previous owner of the given token ID
	     * @param to target address that will receive the tokens
	     * @param tokenId uint256 ID of the token to be transferred
	     * @param _data bytes optional data to send along with the call
	     * @return bool whether the call correctly returned the expected magic value
	     */
	    function _checkOnXRC721Received(address from, address to, uint256 tokenId, bytes memory _data)
	        internal returns (bool)
	    {
	        if (!to.isContract()) {
	            return true;
	        }

	        bytes4 retval = IXRC721Receiver(to).onXRC721Received(msg.sender, from, tokenId, _data);
	        return (retval == _XRC721_RECEIVED);
	    }

	    /**
	     * @dev Private function to clear current approval of a given token ID.
	     * @param tokenId uint256 ID of the token to be transferred
	     */
	    function _clearApproval(uint256 tokenId) private {
	        if (_tokenApprovals[tokenId] != address(0)) {
	            _tokenApprovals[tokenId] = address(0);
	        }
	    }
	}

contracts/OriginalNFTMarketplace.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "./external/IXRC721.sol";
import "./external/ReentrancyGuard.sol";
import "./external/Ownable.sol";

contract OriginalNFTMarketplace is Ownable, ReentrancyGuard {

    // =========================================================================
    //                     ORIGINAL 1/1 NFT MARKETPLACE
    // =========================================================================

    struct OriginalSale {
        address seller;
        address buyer;
        uint256 price;
        uint256 timestamp;
    }

    uint256 public constant TOKEN_ID = 1;
    uint256 public constant MIN_PRICE = 25000 ether;
    uint256 public constant ROYALTY_FRACTION = 1200; // 12% = 1200 basis points
    uint256 private constant FEE_DENOMINATOR = 10000;

    // IXRC721 public originalNFT;
    IXRC721 public immutable originalNFT;
    address public royaltyOwner;
    uint256 public originalPrice;
    OriginalSale[] public originalSalesHistory;
    mapping(address => uint256) public originalOffers;
    address[] public originalBidders;
    mapping(address => uint256) private originalBidderIndex; // 1-indexed (0 = not in array)

    // error OriginalNotSet();
    // error OriginalAlreadySet();
    error OriginalNotApproved();
    error CallerIsOwner();
    error CallerNotOwner();
    error ZeroAddress();
    error PriceBelowMinimum();
    error PriceChanged();
    error PriceMustBeDifferent();
    error InsufficientPayment();
    error TokenNotForSale();
    error TokenAlreadyForSale();
    error NoActiveOffer();
    error OfferMustBeGreater();
    error TransferFailed();

    event OriginalListed(address indexed owner, uint256 price);
    event OriginalDelisted(address indexed owner);
    event OriginalSold(address indexed seller, address indexed buyer, uint256 price);
    event OriginalPriceUpdated(address indexed owner, uint256 newPrice);
    event OriginalOfferMade(address indexed bidder, uint256 amount);
    event OriginalOfferWithdrawn(address indexed bidder, uint256 amount);
    event OriginalOfferAccepted(address indexed owner, address indexed bidder, uint256 amount);
    event RoyaltyOwnerChanged(address indexed oldOwner, address indexed newOwner);

    // constructor(address _royaltyOwner) {
    constructor(address _royaltyOwner, address _originalNFT) {
        if (_royaltyOwner == address(0)) revert ZeroAddress();
        if (_originalNFT == address(0)) revert ZeroAddress();
        royaltyOwner = _royaltyOwner;
        originalNFT = IXRC721(_originalNFT);
    }

    // function setOriginalNFT(address _originalNFT) external onlyOwner {
    //     if (address(originalNFT) != address(0)) revert OriginalAlreadySet();
    //     if (_originalNFT == address(0)) revert ZeroAddress();
    //     originalNFT = IXRC721(_originalNFT);
    // }

    function setRoyaltyOwner(address _newRoyaltyOwner) external {
        if (msg.sender != royaltyOwner) revert CallerNotOwner();
        if (_newRoyaltyOwner == address(0)) revert ZeroAddress();
        emit RoyaltyOwnerChanged(royaltyOwner, _newRoyaltyOwner);
        royaltyOwner = _newRoyaltyOwner;
    }

    // function _requireOriginalSet() internal view {
    //     if (address(originalNFT) == address(0)) revert OriginalNotSet();
    // }

    function _originalOwner() internal view returns (address) {
        return originalNFT.ownerOf(TOKEN_ID);
    }

    function _addBidder(address bidder) internal {
        if (originalBidderIndex[bidder] == 0) {
            originalBidders.push(bidder);
            originalBidderIndex[bidder] = originalBidders.length; // 1-indexed
        }
    }

    function _removeBidder(address bidder) internal {
        uint256 index = originalBidderIndex[bidder];
        if (index == 0) return;
        uint256 lastIndex = originalBidders.length;
        if (index != lastIndex) {
            address lastBidder = originalBidders[lastIndex - 1];
            originalBidders[index - 1] = lastBidder;
            originalBidderIndex[lastBidder] = index;
        }
        originalBidders.pop();
        delete originalBidderIndex[bidder];
    }

    function listOriginal(uint256 price) external {
        // _requireOriginalSet();
        if (_originalOwner() != msg.sender) revert CallerNotOwner();
        if (!originalNFT.isApprovedForAll(msg.sender, address(this))) revert OriginalNotApproved();
        if (price < MIN_PRICE) revert PriceBelowMinimum();
        if (originalPrice > 0) revert TokenAlreadyForSale();

        originalPrice = price;
        emit OriginalListed(msg.sender, price);
    }

    function delistOriginal() external {
        // _requireOriginalSet();
        if (_originalOwner() != msg.sender) revert CallerNotOwner();
        if (originalPrice == 0) revert TokenNotForSale();

        originalPrice = 0;
        emit OriginalDelisted(msg.sender);
    }

    function updateOriginalPrice(uint256 price) external {
        // _requireOriginalSet();
        if (_originalOwner() != msg.sender) revert CallerNotOwner();
        if (originalPrice == 0) revert TokenNotForSale();
        if (price < MIN_PRICE) revert PriceBelowMinimum();
        if (price == originalPrice) revert PriceMustBeDifferent();

        originalPrice = price;
        emit OriginalPriceUpdated(msg.sender, price);
    }

    function buyOriginal(uint256 expectedPrice) external payable nonReentrant {
        // _requireOriginalSet();
        if (originalPrice == 0) revert TokenNotForSale();
        if (_originalOwner() == msg.sender) revert CallerIsOwner();
        if (originalPrice != expectedPrice) revert PriceChanged();
        if (msg.value < originalPrice) revert InsufficientPayment();
        if (!originalNFT.isApprovedForAll(_originalOwner(), address(this))) revert OriginalNotApproved();

        uint256 price = originalPrice;
        address seller = _originalOwner();

        // Effects
        originalPrice = 0;
        originalSalesHistory.push(OriginalSale(seller, msg.sender, price, block.timestamp));

        // Refund buyer's existing offer if any
        uint256 buyerOffer = originalOffers[msg.sender];
        if (buyerOffer > 0) {
            delete originalOffers[msg.sender];
            _removeBidder(msg.sender);
        }

        // Interactions
        originalNFT.transferFrom(seller, msg.sender, TOKEN_ID);

        uint256 royalty = (price * ROYALTY_FRACTION) / FEE_DENOMINATOR;
        uint256 sellerProceeds = price - royalty;

        (bool royaltySuccess, ) = payable(royaltyOwner).call{value: royalty}("");
        if (!royaltySuccess) revert TransferFailed();

        (bool sellerSuccess, ) = payable(seller).call{value: sellerProceeds}("");
        if (!sellerSuccess) revert TransferFailed();

        if (buyerOffer > 0) {
            (bool refundSuccess, ) = payable(msg.sender).call{value: buyerOffer}("");
            if (!refundSuccess) revert TransferFailed();
        }

        if (msg.value > price) {
            (bool overpaySuccess, ) = payable(msg.sender).call{value: msg.value - price}("");
            if (!overpaySuccess) revert TransferFailed();
        }

        emit OriginalSold(seller, msg.sender, price);
    }

    function makeOriginalOffer() external payable nonReentrant {
        // _requireOriginalSet();
        if (_originalOwner() == msg.sender) revert CallerIsOwner();
        if (msg.value == 0) revert PriceBelowMinimum();

        uint256 existingOffer = originalOffers[msg.sender];
        if (msg.value <= existingOffer) revert OfferMustBeGreater();

        // Effects — replace, not accumulate (consistent with XRC721)
        originalOffers[msg.sender] = msg.value;
        _addBidder(msg.sender);

        // Interactions — refund previous offer
        if (existingOffer > 0) {
            (bool success, ) = payable(msg.sender).call{value: existingOffer}("");
            if (!success) revert TransferFailed();
        }

        emit OriginalOfferMade(msg.sender, msg.value);
    }

    function withdrawOriginalOffer() external nonReentrant {
        // _requireOriginalSet();
        uint256 amount = originalOffers[msg.sender];
        if (amount == 0) revert NoActiveOffer();

        // Effects
        delete originalOffers[msg.sender];
        _removeBidder(msg.sender);

        // Interactions
        (bool success, ) = payable(msg.sender).call{value: amount}("");
        if (!success) revert TransferFailed();

        emit OriginalOfferWithdrawn(msg.sender, amount);
    }

    function acceptOriginalOffer(address bidder) external nonReentrant {
        // _requireOriginalSet();
        if (_originalOwner() != msg.sender) revert CallerNotOwner();
        if (!originalNFT.isApprovedForAll(msg.sender, address(this))) revert OriginalNotApproved();

        uint256 offerAmount = originalOffers[bidder];
        if (offerAmount == 0) revert NoActiveOffer();

        // Effects
        delete originalOffers[bidder];
        _removeBidder(bidder);
        originalPrice = 0;
        originalSalesHistory.push(OriginalSale(msg.sender, bidder, offerAmount, block.timestamp));

        // Interactions
        originalNFT.transferFrom(msg.sender, bidder, TOKEN_ID);

        uint256 royalty = (offerAmount * ROYALTY_FRACTION) / FEE_DENOMINATOR;
        uint256 sellerProceeds = offerAmount - royalty;

        (bool royaltySuccess, ) = payable(royaltyOwner).call{value: royalty}("");
        if (!royaltySuccess) revert TransferFailed();

        (bool sellerSuccess, ) = payable(msg.sender).call{value: sellerProceeds}("");
        if (!sellerSuccess) revert TransferFailed();

        emit OriginalOfferAccepted(msg.sender, bidder, offerAmount);
    }

    function getOriginalSalesHistory() external view returns (OriginalSale[] memory) {
        return originalSalesHistory;
    }

    function isOriginalForSale() external view returns (bool) {
        return originalPrice > 0;
    }

    function getOriginalOwner() external view returns (address) {
        // _requireOriginalSet();
        return _originalOwner();
    }

    function getOriginalBidders() external view returns (address[] memory) {
        return originalBidders;
    }

    function getOriginalBiddersCount() external view returns (uint256) {
        return originalBidders.length;
    }
}

contracts/RBTreeInvariantChecker.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "./OrderStatisticsTree.sol";

/// @dev Test-only contract that exposes red-black tree internals for invariant verification
contract RBTreeInvariantChecker {
    using OrderStatisticsTree for OrderStatisticsTree.Tree;
    OrderStatisticsTree.Tree private tree;

    uint256 private constant NULL_NODE = 2**256 - 1;

    function initializeTree() public {
        tree.initializeTree(OrderStatisticsTree.ComparatorType.TOKENID);
    }

    function insert(uint256 tokenId) public {
        tree.insertTokenId(tokenId);
    }

    function remove(uint256 tokenId) public {
        tree.remove(tokenId);
    }

    function size() public view returns (uint256) {
        return tree.nodes[tree.root].size;
    }

    function root() public view returns (uint256) {
        return tree.root;
    }

    function getNode(uint256 id) public view returns (
        uint256 left, uint256 right, uint256 parent,
        uint256 nodeSize, bool isRed, bool initialized
    ) {
        OrderStatisticsTree.Node storage n = tree.nodes[id];
        return (n.left, n.right, n.parent, n.size, n.color == OrderStatisticsTree.Color.RED, n.initialized);
    }

    // ── Invariant 1: Root is black ──
    function checkRootIsBlack() public view returns (bool) {
        if (tree.root == NULL_NODE) return true;
        return tree.nodes[tree.root].color == OrderStatisticsTree.Color.BLACK;
    }

    // ── Invariant 2: No two consecutive red nodes ──
    // Returns true if valid, false if a red node has a red child
    function checkNoConsecutiveRed() public view returns (bool) {
        if (tree.root == NULL_NODE) return true;
        return _checkNoConsecutiveRed(tree.root);
    }

    function _checkNoConsecutiveRed(uint256 nodeId) private view returns (bool) {
        if (nodeId == NULL_NODE) return true;

        OrderStatisticsTree.Node storage node = tree.nodes[nodeId];

        if (node.color == OrderStatisticsTree.Color.RED) {
            // Red node's children must be black
            if (node.left != NULL_NODE && tree.nodes[node.left].color == OrderStatisticsTree.Color.RED) {
                return false;
            }
            if (node.right != NULL_NODE && tree.nodes[node.right].color == OrderStatisticsTree.Color.RED) {
                return false;
            }
        }

        return _checkNoConsecutiveRed(node.left) && _checkNoConsecutiveRed(node.right);
    }

    // ── Invariant 3: Equal black-height on all paths ──
    // Returns the black-height if valid, or 2**256-1 if invalid
    function checkBlackHeight() public view returns (bool) {
        if (tree.root == NULL_NODE) return true;
        return _blackHeight(tree.root) != NULL_NODE;
    }

    function _blackHeight(uint256 nodeId) private view returns (uint256) {
        if (nodeId == NULL_NODE) return 1; // NULL nodes are black

        uint256 leftBH = _blackHeight(tree.nodes[nodeId].left);
        uint256 rightBH = _blackHeight(tree.nodes[nodeId].right);

        // If either subtree is invalid, propagate failure
        if (leftBH == NULL_NODE || rightBH == NULL_NODE) return NULL_NODE;
        // Left and right black-heights must match
        if (leftBH != rightBH) return NULL_NODE;

        // Add 1 if this node is black
        if (tree.nodes[nodeId].color == OrderStatisticsTree.Color.BLACK) {
            return leftBH + 1;
        }
        return leftBH;
    }

    // ── Invariant 4: BST ordering (for TOKENID comparator: left < node < right) ──
    function checkBSTOrdering() public view returns (bool) {
        if (tree.root == NULL_NODE) return true;
        return _checkBST(tree.root, 0, NULL_NODE - 1);
    }

    function _checkBST(uint256 nodeId, uint256 minVal, uint256 maxVal) private view returns (bool) {
        if (nodeId == NULL_NODE) return true;

        uint256 tokenId = tree.nodes[nodeId].tokenId;
        if (tokenId < minVal || tokenId > maxVal) return false;

        // Left subtree: all values < tokenId
        // Right subtree: all values > tokenId
        // Guard against underflow: if tokenId == 0, left subtree must be empty
        bool leftOk = (tokenId == 0)
            ? (tree.nodes[nodeId].left == NULL_NODE)
            : _checkBST(tree.nodes[nodeId].left, minVal, tokenId - 1);

        bool rightOk = (tokenId == NULL_NODE - 1)
            ? (tree.nodes[nodeId].right == NULL_NODE)
            : _checkBST(tree.nodes[nodeId].right, tokenId + 1, maxVal);

        return leftOk && rightOk;
    }

    // ── Invariant 5: Size bookkeeping (node.size = left.size + right.size + 1) ──
    function checkSizeBookkeeping() public view returns (bool) {
        if (tree.root == NULL_NODE) return true;
        return _checkSize(tree.root);
    }

    function _checkSize(uint256 nodeId) private view returns (bool) {
        if (nodeId == NULL_NODE) return true;

        OrderStatisticsTree.Node storage node = tree.nodes[nodeId];
        uint256 leftSize = (node.left == NULL_NODE) ? 0 : tree.nodes[node.left].size;
        uint256 rightSize = (node.right == NULL_NODE) ? 0 : tree.nodes[node.right].size;

        if (node.size != leftSize + rightSize + 1) return false;

        return _checkSize(node.left) && _checkSize(node.right);
    }

    // ── Invariant 6: Parent pointers are consistent ──
    function checkParentPointers() public view returns (bool) {
        if (tree.root == NULL_NODE) return true;
        // Root's parent should be NULL_NODE
        if (tree.nodes[tree.root].parent != NULL_NODE) return false;
        return _checkParent(tree.root);
    }

    function _checkParent(uint256 nodeId) private view returns (bool) {
        if (nodeId == NULL_NODE) return true;

        OrderStatisticsTree.Node storage node = tree.nodes[nodeId];

        if (node.left != NULL_NODE) {
            if (tree.nodes[node.left].parent != nodeId) return false;
        }
        if (node.right != NULL_NODE) {
            if (tree.nodes[node.right].parent != nodeId) return false;
        }

        return _checkParent(node.left) && _checkParent(node.right);
    }

    // ── All invariants at once ──
    function checkAllInvariants() public view returns (
        bool rootBlack,
        bool noConsecutiveRed,
        bool equalBlackHeight,
        bool bstOrdering,
        bool sizeCorrect,
        bool parentPointersCorrect
    ) {
        rootBlack = checkRootIsBlack();
        noConsecutiveRed = checkNoConsecutiveRed();
        equalBlackHeight = checkBlackHeight();
        bstOrdering = checkBSTOrdering();
        sizeCorrect = checkSizeBookkeeping();
        parentPointersCorrect = checkParentPointers();
    }
}
